private readonly i18n = inject(TranslationKeyContractService).keys;
private readonly translate = inject(TranslateService);
private readonly translationRevision = toSignal(
  merge(
    this.translate.onLangChange,
    this.translate.onTranslationChange,
    this.translate.onDefaultLangChange,
  ).pipe(startWith(null)),
  { initialValue: null },
);

protected readonly columnDefs = computed<ColDef[]>(() => {
  this.translationRevision();

  return [
    {
      field: "name",
      headerName: this.translate.instant(this.i18n.workflows.list.columns.name),
    },
  ];
});

protected readonly columnDefs = signal<ColDef[]>([
  { field: "name", headerName: "Name" },
]);

private showSavedToast(): void {
  this.toast.success("Workflow saved");
}
